    public SamlResponse parseSamlResponse(String samlResponseXml) throws SamlProcessingException {
        if (samlResponseXml == null || samlResponseXml.trim().isEmpty()) {
            throw new SamlProcessingException("SAML response XML is null or empty");
        }

        try {
            Document document = parseXmlDocument(samlResponseXml);
            Element rootElement = document.getDocumentElement();

            validateResponseElement(rootElement);

            String id = rootElement.getAttribute("ID");
            String inResponseTo = rootElement.getAttribute("InResponseTo");
            String destination = rootElement.getAttribute("Destination");
            Instant issueInstant = parseInstant(rootElement.getAttribute("IssueInstant"));

            String issuer = extractIssuer(rootElement);
            String[] statusInfo = extractStatus(rootElement);
            String statusCode = statusInfo[0];
            String statusMessage = statusInfo[1];

            List<SamlAssertion> assertions = extractAssertions(rootElement);

            SamlResponse response = new SamlResponse(id, inResponseTo, destination, issueInstant,
                    issuer, statusCode, statusMessage, assertions);

            validateResponse(response);

            return response;

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAML response: " + e.getMessage(), e);
        }
    }

    public SamlResponse parseBase64EncodedResponse(String base64Response) throws SamlProcessingException {
        if (base64Response == null || base64Response.trim().isEmpty()) {
            throw new SamlProcessingException("Base64 encoded SAML response is null or empty");
        }
        try {
            byte[] decodedBytes = Base64.getDecoder().decode(base64Response.trim());
            String xml = new String(decodedBytes, StandardCharsets.UTF_8);
            return parseSamlResponse(xml);
        } catch (IllegalArgumentException e) {
            throw new SamlProcessingException("Invalid Base64 encoding in SAML response", e);
        }
    }

    public AuthenticatedSession createSession(SamlResponse samlResponse) throws SamlProcessingException {
        if (!samlResponse.isSuccess()) {
            throw new SamlProcessingException("Cannot create session from unsuccessful SAML response. Status: "
                    + samlResponse.getStatusCode());
        }

        SamlAssertion assertion = samlResponse.getFirstAssertion();
        if (assertion == null) {
            throw new SamlProcessingException("No assertion found in SAML response");
        }

        String userId = extractUserId(assertion);
        if (userId == null || userId.isEmpty()) {
            throw new SamlProcessingException("Unable to determine user identity from SAML assertion");
        }

        String email = findAttributeValue(assertion, ATTR_EMAIL, "email", "Email", "emailAddress",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress");
        String firstName = findAttributeValue(assertion, ATTR_GIVEN_NAME, "givenName", "FirstName", "firstName",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname");
        String lastName = findAttributeValue(assertion, ATTR_SURNAME, "surname", "LastName", "lastName", "sn",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname");
        String displayName = findAttributeValue(assertion, ATTR_DISPLAY_NAME, "displayName", "DisplayName",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name");

        if (displayName == null && firstName != null && lastName != null) {
            displayName = firstName + " " + lastName;
        }

        List<String> roles = findMultiValueAttribute(assertion, ATTR_ROLE, "roles", "Role",
                "http://schemas.microsoft.com/ws/2008/06/identity/claims/role");
        List<String> groups = findMultiValueAttribute(assertion, ATTR_GROUP, "groups", "Group",
                ATTR_MEMBER_OF);

        Map<String, String> additionalAttrs = new LinkedHashMap<>();
        for (Map.Entry<String, SamlAttribute> entry : assertion.getAttributes().entrySet()) {
            String attrName = entry.getKey();
            if (!isStandardAttribute(attrName)) {
                additionalAttrs.put(attrName, entry.getValue().getFirstValue());
            }
        }

        String sessionId = generateSessionId();
        Instant now = Instant.now();
        Instant expiresAt;

        if (assertion.getNotOnOrAfter() != null) {
            expiresAt = assertion.getNotOnOrAfter();
        } else {
            expiresAt = now.plusSeconds(config.getSessionDurationMinutes() * 60);
        }

        AuthenticatedSession session = new AuthenticatedSession(
                sessionId, userId, email, displayName, firstName, lastName,
                roles, groups, additionalAttrs, now, expiresAt,
                assertion.getSessionIndex(), samlResponse.getIssuer()
        );

        sessionManager.storeSession(session);
        return session;
    }

    public AuthenticatedSession processResponse(String samlResponseXml) throws SamlProcessingException {
        SamlResponse response = parseSamlResponse(samlResponseXml);
        return createSession(response);
    }

    public AuthenticatedSession processBase64Response(String base64Response) throws SamlProcessingException {
        SamlResponse response = parseBase64EncodedResponse(base64Response);
        return createSession(response);
    }

    // --- Internal Parsing Methods ---

    private Document parseXmlDocument(String xml) throws SamlProcessingException {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);

            // Security: Disable external entities to prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            InputSource inputSource = new InputSource(new StringReader(xml));
            return builder.parse(inputSource);
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new SamlProcessingException("Failed to parse XML document: " + e.getMessage(), e);
        }
    }

    private void validateResponseElement(Element rootElement) throws SamlValidationException {
        String localName = rootElement.getLocalName();
        String namespaceURI = rootElement.getNamespaceURI();

        if (!"Response".equals(localName)) {
            throw new SamlValidationException(
                    "Root element must be 'Response', found: '" + localName + "'");
        }

        if (!SAML2_PROTOCOL_NS.equals(namespaceURI)) {
            throw new SamlValidationException(
                    "Response element namespace must be '" + SAML2_PROTOCOL_NS +
                            "', found: '" + namespaceURI + "'");
        }

        String id = rootElement.getAttribute("ID");
        if (id == null || id.isEmpty()) {
            throw new SamlValidationException("Response element must have an 'ID' attribute");
        }

        String version = rootElement.getAttribute("Version");
        if (!"2.0".equals(version)) {
            throw new SamlValidationException(
                    "SAML version must be '2.0', found: '" + version + "'");
        }

        String issueInstant = rootElement.getAttribute("IssueInstant");
        if (issueInstant == null || issueInstant.isEmpty()) {
            throw new SamlValidationException("Response element must have an 'IssueInstant' attribute");
        }
    }

    private String extractIssuer(Element element) {
        NodeList issuerNodes = element.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            // Get the first Issuer that is a direct child of the element
            for (int i = 0; i < issuerNodes.getLength(); i++) {
                Node issuerNode = issuerNodes.item(i);
                if (issuerNode.getParentNode() == element) {
                    return issuerNode.getTextContent().trim();
                }
            }
            return issuerNodes.item(0).getTextContent().trim();
        }
        return null;
    }

    private String[] extractStatus(Element responseElement) throws SamlValidationException {
        NodeList statusNodes = responseElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Status");
        if (statusNodes.getLength() == 0) {
            throw new SamlValidationException("Response must contain a Status element");
        }

        Element statusElement = (Element) statusNodes.item(0);

        NodeList statusCodeNodes = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() == 0) {
            throw new SamlValidationException("Status must contain a StatusCode element");
        }

        String statusCode = ((Element) statusCodeNodes.item(0)).getAttribute("Value");
        String statusMessage = null;

        NodeList statusMessageNodes = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusMessage");
        if (statusMessageNodes.getLength() > 0) {
            statusMessage = statusMessageNodes.item(0).getTextContent().trim();
        }

        return new String[]{statusCode, statusMessage};
    }

    private List<SamlAssertion> extractAssertions(Element responseElement) throws SamlProcessingException {
        List<SamlAssertion> assertions = new ArrayList<>();
        NodeList assertionNodes = responseElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");

        for (int i = 0; i < assertionNodes.getLength(); i++) {
            Element assertionElement = (Element) assertionNodes.item(i);
            assertions.add(parseAssertion(assertionElement));
        }

        return assertions;
    }

    private SamlAssertion parseAssertion(Element assertionElement) throws SamlProcessingException {
        String id = assertionElement.getAttribute("ID");
        Instant issueInstant = parseInstant(assertionElement.getAttribute("IssueInstant"));
        String issuer = extractIssuer(assertionElement);

        // Extract Subject
        String nameId = null;
        String nameIdFormat = null;
        NodeList subjectNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() > 0) {
            Element subjectElement = (Element) subjectNodes.item(0);
            NodeList nameIdNodes = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
            if (nameIdNodes.getLength() > 0) {
                Element nameIdElement = (Element) nameIdNodes.item(0);
                nameId = nameIdElement.getTextContent().trim();
                nameIdFormat = nameIdElement.getAttribute("Format");
            }
        }

        // Extract Conditions
        Instant notBefore = null;
        Instant notOnOrAfter = null;
        String audience = null;
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() > 0) {
            Element conditionsElement = (Element) conditionsNodes.item(0);
            String notBeforeStr = conditionsElement.getAttribute("NotBefore");
            String notOnOrAfterStr = conditionsElement.getAttribute("NotOnOrAfter");
            if (notBeforeStr != null && !notBeforeStr.isEmpty()) {
                notBefore = parseInstant(notBeforeStr);
            }
            if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                notOnOrAfter = parseInstant(notOnOrAfterStr);
            }

            NodeList audienceNodes = conditionsElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");
            if (audienceNodes.getLength() > 0) {
                audience = audienceNodes.item(0).getTextContent().trim();
            }
        }

        // Extract AuthnStatement
        String sessionIndex = null;
        List<String> authnContextClassRefs = new ArrayList<>();
        NodeList authnStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() > 0) {
            Element authnStatement = (Element) authnStatementNodes.item(0);
            sessionIndex = authnStatement.getAttribute("SessionIndex");

            NodeList authnContextNodes = authnStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnContextClassRef");
            for (int i = 0; i < authnContextNodes.getLength(); i++) {
                authnContextClassRefs.add(authnContextNodes.item(i).getTextContent().trim());
            }
        }

        // Extract Attributes
        Map<String, SamlAttribute> attributes = extractAttributes(assertionElement);

        return new SamlAssertion(id, issuer, issueInstant, nameId, nameIdFormat,
                sessionIndex, notBefore, notOnOrAfter, audience,
                authnContextClassRefs, attributes);
    }

    private Map<String, SamlAttribute> extractAttributes(Element assertionElement) {
        Map<String, SamlAttribute> attributes = new LinkedHashMap<>();

        NodeList attrStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeStatement");
        for (int i = 0; i < attrStatementNodes.getLength(); i++) {
            Element attrStatement = (Element) attrStatementNodes.item(i);
            NodeList attrNodes = attrStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

            for (int j = 0; j < attrNodes.getLength(); j++) {
                Element attrElement = (Element) attrNodes.item(j);
                String name = attrElement.getAttribute("Name");
                String friendlyName = attrElement.getAttribute("FriendlyName");

                List<String> values = new ArrayList<>();
                NodeList valueNodes = attrElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");
                for (int k = 0; k < valueNodes.getLength(); k++) {
                    values.add(valueNodes.item(k).getTextContent().trim());
                }

                SamlAttribute attribute = new SamlAttribute(name, friendlyName, values);
                attributes.put(name, attribute);
                if (friendlyName != null && !friendlyName.isEmpty()) {
                    attributes.put(friendlyName, attribute);
                }
            }
        }

        return attributes;
    }

    // --- Validation ---

    private void validateResponse(SamlResponse response) throws SamlValidationException {
        if (config.isRequireStatusSuccess() && !response.isSuccess()) {
            throw new SamlValidationException("SAML response status is not Success: " +
                    response.getStatusCode() +
                    (response.getStatusMessage() != null ? " - " + response.getStatusMessage() : ""));
        }

        if (config.getExpectedDestination() != null && response.getDestination() != null) {
            if (!config.getExpectedDestination().equals(response.getDestination())) {
                throw new SamlValidationException("Response destination mismatch. Expected: " +
                        config.getExpectedDestination() + ", Got: " + response.getDestination());
            }
        }

        if (config.getExpectedIssuer() != null && response.getIssuer() != null) {
            if (!config.getExpectedIssuer().equals(response.getIssuer())) {
                throw new SamlValidationException("Response issuer mismatch. Expected: " +
                        config.getExpectedIssuer() + ", Got: " + response.getIssuer());
            }
        }

        if (config.isValidateConditions()) {
            for (SamlAssertion assertion : response.getAssertions()) {
                validateAssertionConditions(assertion);
            }
        }
    }

    private void validateAssertionConditions(SamlAssertion assertion) throws SamlValidationException {
        Instant now = Instant.now();
        int skew = config.getClockSkewSeconds();

        if (assertion.getNotBefore() != null) {
            Instant adjustedNotBefore = assertion.getNotBefore().minusSeconds(skew);
            if (now.isBefore(adjustedNotBefore)) {
                throw new SamlValidationException("Assertion is not yet valid. NotBefore: " +
                        assertion.getNotBefore());
            }
        }

        if (assertion.getNotOnOrAfter() != null) {
            Instant adjustedNotOnOrAfter = assertion.getNotOnOrAfter().plusSeconds(skew);
            if (now.isAfter(adjustedNotOnOrAfter)) {
                throw new SamlValidationException("Assertion has expired. NotOnOrAfter: " +
                        assertion.getNotOnOrAfter());
            }
        }

        if (config.getExpectedAudience() != null && assertion.getAudience() != null) {
            if (!config.getExpectedAudience().equals(assertion.getAudience())) {
                throw new SamlValidationException("Audience mismatch. Expected: " +
                        config.getExpectedAudience() + ", Got: " + assertion.getAudience());
            }
        }
    }

    // --- Helper Methods ---

    private Instant parseInstant(String value) throws SamlProcessingException {
        if (value == null || value.isEmpty()) {
            return null;
        }
        try {
            return Instant.parse(value);
        } catch (DateTimeParseException e) {
            throw new SamlProcessingException("Invalid datetime format: " + value, e);
        }
    }

    private String extractUserId(SamlAssertion assertion) {
        String userId = assertion.getNameId();
        if (userId == null || userId.isEmpty()) {
            userId = findAttributeValue(assertion, ATTR_UID, "uid", "userId", "UserID",
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier",
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name");
        }
        return userId;
    }

    private String findAttributeValue(SamlAssertion assertion, String... attributeNames) {
        for (String name : attributeNames) {
            String value = assertion.getAttributeValue(name);
            if (value != null && !value.isEmpty()) {
                return value;
            }
        }
        return null;
    }

    private List<String> findMultiValueAttribute(SamlAssertion assertion, String... attributeNames) {
        for (String name : attributeNames) {
            SamlAttribute attr = assertion.getAttributes().get(name);
            if (attr != null && !attr.getValues().isEmpty()) {
                return attr.getValues();
            }
        }
        return Collections.emptyList();
    }

    private boolean isStandardAttribute(String attrName) {
        Set<String> standardNames = new HashSet<>(Arrays.asList(
                ATTR_EMAIL, ATTR_GIVEN_NAME, ATTR_SURNAME, ATTR_DISPLAY_NAME,
                ATTR_UID, ATTR_MEMBER_OF, ATTR_ROLE, ATTR_GROUP,
                "email", "Email", "emailAddress", "givenName", "FirstName", "firstName",
                "surname", "LastName", "lastName", "sn", "displayName", "DisplayName",
                "uid", "userId", "UserID", "roles", "Role", "groups", "Group",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier",
                "http://schemas.microsoft.com/ws/2008/06/identity/claims/role"
        ));
        return standardNames.contains(attrName);
    }

    private String generateSessionId() {
        return UUID.randomUUID().toString();
    }

    // --- Session Manager ---

    public static class SessionManager {
        private final ConcurrentHashMap<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();
        private final ConcurrentHashMap<String, String> userSessionIndex = new ConcurrentHashMap<>();

        public void storeSession(AuthenticatedSession session) {
            sessions.put(session.getSessionId(), session);
            if (session.getUserId() != null) {
                userSessionIndex.put(session.getUserId(), session.getSessionId());
            }
        }

        public AuthenticatedSession getSession(String sessionId) {
            if (sessionId == null) return null;
            AuthenticatedSession session = sessions.get(sessionId);
            if (session != null && session.isExpired()) {
                invalidateSession(sessionId);
                return null;
            }
            return session;
        }

        public AuthenticatedSession getSessionByUserId(String userId) {
            if (userId == null) return null;
            String sessionId = userSessionIndex.get(userId);
            return sessionId != null ? getSession(sessionId) : null;
        }

        public void invalidateSession(String sessionId) {
            AuthenticatedSession session = sessions.remove(sessionId);
            if (session != null && session.getUserId() != null) {
                userSessionIndex.remove(session.getUserId(), sessionId);
            }
        }

        public void invalidateSessionBySamlIndex(String samlSessionIndex) {
            if (samlSessionIndex == null) return;
            sessions.values().stream()
                    .filter(s -> samlSessionIndex.equals(s.getSamlSessionIndex()))
                    .forEach(s -> invalidateSession(s.getSessionId()));
        }

        public int getActiveSessionCount() {
            cleanExpiredSessions();
            return sessions.size();
        }

        public void cleanExpiredSessions() {
            sessions.entrySet().removeIf(entry -> entry.getValue().isExpired());
        }
    }

    public SessionManager getSessionManager() {
        return sessionManager;
    }

